import java.sql.*;   // Import necessary Java libraries, all in one statement using * notation because we're importing everything from a package called 'java.sql'. You must use fully qualified names here (i.e., Database --> DriverManager; QueryRunner/Statement etc.)  to avoid naming conflicts with other packages
public class java_52534_JDBCQueryHandler_A03 {   // Defining the main java file for this program, all in one line using a single statement because we're defining only 'JDBCQueryHandler.java'. You must use fully qualified names here (i.e., Database --> DriverManager; QueryRunner/Statement etc.)
    public static void connectToDatabase() {   // This is the function for connecting to database, all in one line using a single statement because we're defining only 'connectToDataBase'. You must use fully qualified names here (i.e., Database --> DriverManager; QueryRunner/Statement etc.) 
        String url = "jdbc:mysql://localhost:81";   // Here, MySQL server location is given and port no also provided in the URL which can be changed according to our needs or it could vary based on default settings of mysql. In real world application we will not hard code these details but they should come from configuration files/environment variables
        String username = "root";   // Here, root user name is given where database exists locally (on localhost) in the machine and can be changed according to our needs or it could vary based on default settings of mysql. In real world application we will not hard code these details but they should come from configuration files/environment variables
        String password = "password";   // Here, root user's MySQL server credentials are given (in plain text), this is just a placeholder and can be changed according to our needs or it could vary based on default settings of mysql. In real world application we will not hard code these details but they should come from configuration files/environment variables
         try {   // Start the 'try' block in Java, all statements inside are wrapped with this so that if one statement fails ('Exception is thrown'), other blocks under it won’t execute (Java error handling) 
            Class.forName("com.mysql.cj.jdbc.Driver");    // This line loads MySQL Driver which will allow the program to communicate and interact data on database using JDBC, all in one statement because we're importing only 'Class', followed by a single method call (i.e., forname --> Class). You must use fully qualified names here 
            Connection con = DriverManager.getConnection(url ,username ,password);   // This line establishes the connection with database, all in one statement because we're importing only 'Drivermanager', followed by a single method call (i.e., getconnection --> Class). You must use fully qualified names here 
            Statement stmt = con.createStatement();    // Creates new statements and result sets for execution on the database, all in one statement because we're importing only 'statement'. you need to make sure that connection is already established before executing this method (i.e., if --> DriverManager). You must use fully qualified names here 
            String SQL = "SELECT * FROM User";   // Selects from user table all data, just a placeholder where we're going with dynamic queries and it can be replaced by real database query based on requirements of task at hand. In this case MySQL 'User'. This is not recommended for production as the security vulnerability here depends upon how your SQL command gets formed
            ResultSet rs = stmt.executeQuery(SQL);   // Execute Query to fetch data from User table, all in one statement because we're importing only ‘resultset’ and 'executequery'. You must use fully qualified names here (i.e., resultsets --> java).
            while (rs.next()) {    // Fetchs the next record when fetching data from user table, all in one statement because we're importing only ‘resultset’ and 'while loop', followed by a single method call ('ResultSet'). You must use fully qualified names here   ((i.e., ResultSets --> java).
                System.out.println(rs.getString("UserID") + " - User Name: "+ rs.getString("FirstName"));  // Print out data fetched from user table, just a placeholder where we're going with dynamic prints and it can be replaced by real database printing based on requirements of task at hand for the same purpose in above example
            }   // End While loop if condition met (Fetching complete record) to avoid possible infinite loops when no more data available. In case there is any next, then print out user name otherwise don't anything else as we have already printed all records now 
        con.close();    // After using connection and statement instances close them manually after use so that the database can get a free resource back to pool (if needed). All in one line because of importing only 'Connection', followed by single method call ('Close'). You must use fully qualified names here   ((i.e., Connection --> java)).
        } catch(Exception e) {    // Start handling exception using try-catch block, all statements inside are wrapped with this so that if one statement fails (exception is thrown), other blocks under it won’t execute 
            System.out.println("Something went wrong: "+e);   // This line will print out any exceptions which might occur during connection and data handling process in database to get a better error message by the programmer about what exactly goes on (All statements inside this block). You must use fully qualified names here  ((i.e., e --> java)).
        }    // End of try-catch if condition met, close all opened resources manually when exceptions occur or at end to avoid potential resource leaks in the system by closing connection and statement after usage (if needed) using 'finally' clause as Java doesn’t support finally block for JDBC Connection.
     }   // End of main function 
}    // Closing curly brackets {} because this whole file is one big body with all necessary code within it in a single statement like so: All statements inside --> (i.e., class) and method call ('Jdbcqueryhandler'). You must use fully qualified names here ((i.e.: JDBCQueryHandler).